    {
      "keystrokes": "cat > program.py << 'PY'
#!/usr/bin/env python3
import os
from pathlib import Path

def read_bytes(path):
    with open(path, 'rb') as f:
        return f.read()

def write_bytes(path, data):
    with open(path, 'wb') as f:
        f.write(data)

def chunk_records(data, rec_len):
    if len(data) % rec_len != 0:
        # Allow last partial record if present; COBOL uses fixed-length; files here are exact multiples.
        pass
    return [data[i:i+rec_len] for i in range(0, len(data), rec_len)]

def parse_accounts(data):
    recs = []
    for rec in chunk_records(data, 34):
        s = rec.decode('ascii')
        acc_id = s[0:4]
        name = s[4:24]
        balance_str = s[24:34]
        balance = int(balance_str)
        recs.append({'id': acc_id, 'name': name, 'balance': balance})
    return recs

def serialize_accounts(recs):
    out = []
    for r in recs:
        acc_id = r['id']
        name = r['name']  # already fixed-width 20
        bal = r['balance']
        bal_str = f"{bal:010d}"
        out.append((acc_id + name + bal_str).encode('ascii'))
    return b''.join(out)

def parse_books(data):
    recs = []
    for rec in chunk_records(data, 28):
        s = rec.decode('ascii')
        book_id = s[0:4]
        title = s[4:24]
        owner = s[24:28]
        recs.append({'id': book_id, 'title': title, 'owner': owner})
    return recs

def serialize_books(recs):
    out = []
    for r in recs:
        out.append((r['id'] + r['title'] + r['owner']).encode('ascii'))
    return b''.join(out)

def parse_transactions(data):
    recs = []
    for rec in chunk_records(data, 22):
        s = rec.decode('ascii')
        book = s[0:4]
        amount = int(s[4:14])
        seller = s[14:18]
        buyer = s[18:22]
        recs.append({'book': book, 'amount': amount, 'seller': seller, 'buyer': buyer})
    return recs

def serialize_transaction(rec):
    amt_str = f"{rec['amount']:010d}"
    return (rec['book'] + amt_str + rec['seller'] + rec['buyer']).encode('ascii')

def main():
    base = Path('.')
    input_path = base / 'src' / 'INPUT.DAT'
    accounts_path = base / 'data' / 'ACCOUNTS.DAT'
    books_path = base / 'data' / 'BOOKS.DAT'
    transactions_path = base / 'data' / 'TRANSACTIONS.DAT'

    # Read input
    if not input_path.exists():
        print('Error: Input file is empty')
        return
    inp = read_bytes(input_path).decode('ascii')
    if len(inp) == 0:
        print('Error: Input file is empty')
        return
    buyer_id = inp[0:4]
    seller_id = inp[4:8]
    book_id = inp[8:12]
    amount_str = inp[12:]
    amount_str = amount_str.strip()
    amount = int(amount_str) if amount_str else 0

    # Initialize flags
    buyer_found = 'N'
    seller_found = 'N'
    book_found = 'N'
    valid_owner = 'N'

    # Validate accounts
    accs = parse_accounts(read_bytes(accounts_path))
    for a in accs:
        if a['id'] == buyer_id:
            buyer_found = 'Y'
        if a['id'] == seller_id:
            seller_found = 'Y'

    # Validate books
    books = parse_books(read_bytes(books_path))
    for b in books:
        if b['id'] == book_id:
            book_found = 'Y'
            if b['owner'] == seller_id:
                valid_owner = 'Y'

    print('')  # DISPLAY " " in COBOL

    if buyer_found == 'Y' and seller_found == 'Y' and book_found == 'Y' and valid_owner == 'Y':
        # Process transaction
        # Update accounts
        for a in accs:
            if a['id'] == buyer_id:
                a['balance'] = a['balance'] - amount
            if a['id'] == seller_id:
                a['balance'] = a['balance'] + amount
        write_bytes(accounts_path, serialize_accounts(accs))

        # Update book owner
        for b in books:
            if b['id'] == book_id:
                b['owner'] = buyer_id
        write_bytes(books_path, serialize_books(books))

        # Append transaction
        new_tx = {'book': book_id, 'amount': amount, 'seller': seller_id, 'buyer': buyer_id}
        with open(transactions_path, 'ab') as f:
            f.write(serialize_transaction(new_tx))

        print('Transaction completed successfully')
    else:
        print('Transaction failed due to validation errors')

if __name__ == '__main__':
    main()
